              style={{ top: CENTER_INDEX * ITEM_HEIGHT + ITEM_HEIGHT / 2 - 8 }}
            >
              <svg width="12" height="16" viewBox="0 0 12 16" fill="currentColor">
                <path d="M0 8L12 0V16L0 8Z" />
              </svg>
            </div>
          </>
        )}

        {/* Scrolling reel */}
        <motion.div animate={controls} style={{ y: 0 }}>
          {displayItems.map((item, i) => {
            const scale = getWeightScale(item)
            const isCenter = !isSpinning && hasResult && i === displayItems.length - VISIBLE_COUNT + CENTER_INDEX

            return (
              <div
                key={`${item.id}-${i}`}
                className={`flex items-center justify-center px-6 select-none transition-colors ${
                  isCenter
                    ? 'text-indigo-700 dark:text-indigo-300 font-bold'
                    : 'text-gray-700 dark:text-gray-300'
                }`}
                style={{ height: ITEM_HEIGHT }}
