import React, { useEffect, useRef, useMemo, useCallback } from 'react'
import { motion, useAnimationControls } from 'framer-motion'
import confetti from 'canvas-confetti'
import { ListItem } from '../../context/ListsContext'

interface SpinnerAnimationProps {
  items: ListItem[]
  targetItem: ListItem | null
  isSpinning: boolean
  hasResult: boolean
  useWeights?: boolean
  onSpinComplete?: () => void
}

const ITEM_HEIGHT = 56
const VISIBLE_COUNT = 5
const VIEWPORT_HEIGHT = ITEM_HEIGHT * VISIBLE_COUNT
const CENTER_INDEX = Math.floor(VISIBLE_COUNT / 2)

const SpinnerAnimation: React.FC<SpinnerAnimationProps> = ({
  items,
  targetItem,
  isSpinning,
  hasResult,
  useWeights = false,
  onSpinComplete
}) => {
  const controls = useAnimationControls()
  const viewportRef = useRef<HTMLDivElement>(null)
  const reelRef = useRef<ListItem[]>([])
  const hasTriggeredConfetti = useRef(false)
  const spinIdRef = useRef(0)

  // Build idle display items (pad if fewer than VISIBLE_COUNT)
  const idleItems = useMemo(() => {
    if (items.length === 0) return []
    const result: ListItem[] = []
    while (result.length < VISIBLE_COUNT) {
      result.push(...items)
    }
    return result.slice(0, VISIBLE_COUNT)
  }, [items])

  // Build the reel for spinning
  const buildReel = useCallback(() => {
    if (items.length === 0 || !targetItem) return []

    const others = items.filter(it => it.id !== targetItem.id)
    const getOther = () =>
      others.length > 0
        ? others[Math.floor(Math.random() * others.length)]
        : targetItem

    const reel: ListItem[] = []

    // Add several shuffled cycles for the spin duration
    const cycles = Math.max(6, Math.ceil(40 / items.length))
    for (let c = 0; c < cycles; c++) {
      const shuffled = [...items].sort(() => Math.random() - 0.5)
      reel.push(...shuffled)
    }

    // Landing strip: last VISIBLE_COUNT items with target at center
    const landing: ListItem[] = []
    for (let i = 0; i < VISIBLE_COUNT; i++) {
      if (i === CENTER_INDEX) {
        landing.push(targetItem)
      } else {
        landing.push(getOther())
      }
    }
    reel.push(...landing)

    return reel
  }, [items, targetItem])

  // Start spin animation
  useEffect(() => {
    if (!isSpinning || !targetItem) return

    hasTriggeredConfetti.current = false
    const reel = buildReel()
    reelRef.current = reel
    spinIdRef.current++
    const currentSpinId = spinIdRef.current

    const totalScroll = (reel.length - VISIBLE_COUNT) * ITEM_HEIGHT

    // Reset to top, then animate to final position
    controls.set({ y: 0 })
    controls.start({
      y: -totalScroll,
      transition: {
        duration: 2.8 + Math.random() * 0.8,
        ease: [0.12, 0, 0.2, 1], // aggressive deceleration curve
      }
    }).then(() => {
      if (spinIdRef.current === currentSpinId) {
        onSpinComplete?.()
      }
    })
  }, [isSpinning, targetItem, buildReel, controls, onSpinComplete])

  // Fire confetti when result settles
  useEffect(() => {
    if (hasResult && !hasTriggeredConfetti.current && viewportRef.current) {
      hasTriggeredConfetti.current = true
      const rect = viewportRef.current.getBoundingClientRect()
      const x = (rect.left + rect.width / 2) / window.innerWidth
      const y = (rect.top + rect.height / 2) / window.innerHeight

      confetti({
        particleCount: 40,
        spread: 70,
        origin: { x, y },
        colors: ['#4f46e5', '#7c3aed', '#ec4899', '#f59e0b', '#10b981'],
      })
    }
  }, [hasResult])

  const displayItems = isSpinning || hasResult ? reelRef.current : idleItems
  const showHighlight = isSpinning || hasResult

  // Weight-based font scale
  const getWeightScale = (item: ListItem) => {
    if (!useWeights) return 1
    const maxWeight = Math.max(...items.map(i => i.weight ?? 1))
    if (maxWeight <= 1) return 1
    const w = item.weight ?? 1
    return 1 + ((w - 1) / (maxWeight - 1)) * 0.25
  }

  return (
    <div className="relative w-72 mx-auto" ref={viewportRef}>
      {/* "Your pick" label */}
      {hasResult && targetItem && (
        <motion.div
          initial={{ opacity: 0, y: -8 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.2, duration: 0.3 }}
          className="text-center mb-2"
        >
          <span className="text-xs font-medium uppercase tracking-wider text-indigo-500 dark:text-indigo-400">
            Your pick
          </span>
        </motion.div>
      )}

      {/* Wheel viewport */}
      <div
        className="relative overflow-hidden rounded-xl border border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 shadow-lg"
        style={{ height: VIEWPORT_HEIGHT }}
      >
        {/* Gradient masks for edge fade */}
        <div className="absolute inset-x-0 top-0 h-16 bg-gradient-to-b from-white dark:from-gray-800 to-transparent z-10 pointer-events-none rounded-t-xl" />
        <div className="absolute inset-x-0 bottom-0 h-16 bg-gradient-to-t from-white dark:from-gray-800 to-transparent z-10 pointer-events-none rounded-b-xl" />

        {/* Center highlight band */}
        {showHighlight && (
          <div
            className="absolute inset-x-0 z-[5] pointer-events-none border-y-2 border-indigo-500 dark:border-indigo-400 bg-indigo-50/50 dark:bg-indigo-900/20"
            style={{
              top: CENTER_INDEX * ITEM_HEIGHT,
              height: ITEM_HEIGHT,
            }}
          />
        )}

        {/* Pointer arrows */}
        {showHighlight && (
          <>
            <div
              className="absolute left-1 z-20 text-indigo-500 dark:text-indigo-400 pointer-events-none"
              style={{ top: CENTER_INDEX * ITEM_HEIGHT + ITEM_HEIGHT / 2 - 8 }}
            >
              <svg width="12" height="16" viewBox="0 0 12 16" fill="currentColor">
                <path d="M0 0V16L12 8Z" />
