            </div>
          </>
        )}

        {/* Scrolling reel */}
        <motion.div animate={controls} style={{ y: 0 }}>
          {displayItems.map((item, i) => {
            const scale = getWeightScale(item)
            const isCenter = !isSpinning && hasResult && i === displayItems.length - VISIBLE_COUNT + CENTER_INDEX

            return (
              <div
                key={`${item.id}-${i}`}
                className={`flex items-center justify-center px-6 select-none transition-colors ${
                  isCenter
                    ? 'text-indigo-700 dark:text-indigo-300 font-bold'
                    : 'text-gray-700 dark:text-gray-300'
                }`}
                style={{ height: ITEM_HEIGHT }}
              >
                <span
                  className="truncate text-center w-full"
                  style={{ fontSize: `${scale}rem` }}
                >
                  {item.text}
                </span>
              </div>
            )
          })}
        </motion.div>

        {/* Settled glow effect */}
        {hasResult && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: [0, 0.6, 0.3] }}
            transition={{ duration: 1.5, ease: 'easeOut' }}
            className="absolute inset-x-0 z-[3] rounded-xl pointer-events-none"
            style={{
              top: CENTER_INDEX * ITEM_HEIGHT,
              height: ITEM_HEIGHT,
              boxShadow: '0 0 20px 4px rgba(99, 102, 241, 0.3)',
            }}
          />
        )}
      </div>
    </div>
  )
}

export default SpinnerAnimation

